"use client";
import { useParams } from "next/navigation";
import { useRouter } from "next/navigation";
import React, { useEffect, useRef, useState } from "react";
import { client, notify } from "@/utils/helper";
import Select from "react-select";
export default function page() {
  const { slug } = useParams();
//   console.log(slug);
//   return
  const router = useRouter();
  const [loader, setLoader] = useState(false);
  const nameRef = useRef(null);
  const slugRef = useRef(null);
  const fileRef = useRef(null);
  const [data, setData] = useState({})
  const [image, setImage] = useState("")
  const[category,setCategory] = useState([])
 const [slecategories,setCategoryId] = useState([])
  
//   console.log(image)

function categorySelect(cat){
    // console.log(cat)
    const ids =  cat.map((data)=> data.value)
    setCategoryId(ids)
  }

  function createSlug(text) {
    return text
      .toLowerCase()
      .trim()
      .replace(/[^\w\s-]/g, "")
      .replace(/\s+/g, "-")
      .replace(/-+/g, "-");
  }

  function getSlug() {
    let value = nameRef.current.value;
    slugRef.current.value = createSlug(value);
  }

  useEffect(() => {
    if (!slug) return;
    client
      .get(`brand/slug/${slug}`)
      .then((response) => {
        const formdata = response.data.data;
        // console.log(formdata)
        const meta = response.data.meta
        const imagename = (response.data.data.image)
        setImage(imagename)
        setData(formdata[0]);
      })
      .catch((error) => {
        console.log(error);
      });
  }, [slug]);

  useEffect(
    ()=>{
         const fetchData = async () => {
              try {
                const data = await getCategories();
                setCategory(data.data);
              } catch (error) {
                console.log(error);
              }
            };
          
            fetchData();
    },
    []
  )
//   return
  const submitHandler = (e) => {
    e.preventDefault();
    const image = e.target.image.files[0]
    // console.log()
    const payload = new FormData();
    if (e.target.image.files[0]) {
      payload.append("image", e.target.image.files[0]);
    }
    payload.append("name", nameRef.current.value);
    payload.append("slug", slugRef.current.value);
    payload.append("categoryId", JSON.stringify(slecategories)  )
    console.log(payload);
    setLoader(true);
    client
      .put(`/brand/edit/${slug}`, payload)
      .then((response) => {
        if (response.data.success) {
          notify(response.data.masg, response.data.success);
        }
        router.push("/admin/category");
      })
      .catch((error) => {
        const massage = error?.response?.data?.masg || "Internal server error";
        notify(massage, false);
        console.log(error);
      })
      .finally(() => {
        setLoader(false);
      });
    e.target.reset();
  };
  return (
    <div className="min-h-screen bg-gray-50 flex justify-center items-start p-8">
    <div className="w-full max-w-3xl bg-white rounded-2xl border border-gray-200 p-8">
      
      {/* Header */}
      <div className="mb-8">
        <h2 className="text-2xl font-semibold text-gray-800 flex items-center gap-2">
          ✏️ Edit Brand
        </h2>
        <p className="text-sm text-gray-500 mt-1">
          Update your brand details below
        </p>
      </div>
  
      {/* Form */}
      <form onSubmit={submitHandler} className="space-y-6">
        
        {/* Name + Slug */}
        <div className="grid grid-cols-2 gap-6">
          
          {/* Name */}
          <div className="space-y-2">
            <label className="text-sm text-gray-500">
              🏷️ Brand Name
            </label>
            <input
              onChange={getSlug}
              type="text"
              defaultValue={data.name}
              ref={nameRef}
              placeholder="Enter brand name"
              className="w-full px-4 py-2.5 rounded-lg bg-white border border-gray-200 text-sm
              focus:ring-2 focus:ring-orange-400 focus:border-orange-400 outline-none"
            />
          </div>
  
          {/* Slug */}
          <div className="space-y-2">
            <label className="text-sm text-gray-500">
              🔗 Slug
            </label>
            <input
              type="text"
              ref={slugRef}
              defaultValue={data.slug}
              placeholder="enter-slug"
              className="w-full px-4 py-2.5 rounded-lg bg-white border border-gray-200 text-sm
              focus:ring-2 focus:ring-orange-400 focus:border-orange-400 outline-none"
            />
          </div>

          <Select
              onChange={categorySelect}
              isMulti
              closeMenuOnSelect={false}
              options={category.map((cat) => ({
                value: cat._id,
                label: cat.name,
              }))}
            />
        </div>
  
        {/* Image Upload */}
        <div className="space-y-3">
          <label className="text-sm text-gray-500">
            🖼️ Brand Image
          </label>
  
          <label className="w-full h-36 flex flex-col items-center justify-center gap-2 rounded-xl border border-dashed border-gray-300 bg-gray-50 cursor-pointer hover:bg-gray-100 transition">
            
            <span className="text-2xl">📁</span>
  
            <span className="text-sm text-gray-500">
              Click to upload image
            </span>
  
            {/* ✅ Added logic: show selected file name */}
            <span className="text-xs text-gray-400">
              {fileRef?.current?.files?.[0]?.name || "No file selected"}
            </span>
  
            <span className="text-xs px-3 py-1 bg-orange-500 text-white rounded-md">
              Browse File
            </span>
  
            <input
              type="file"
              ref={fileRef}
              name="image"
              className="hidden"
            />
          </label>
  
          {/* Preview */}
          <div>
            <img
              width={100}
              className="rounded-lg mt-2 border border-gray-200"
              src={`http://localhost:5000/brand/${data.image}`}
              alt=""
            />
          </div>
        </div>
  
        {/* Actions */}
        <div className="flex justify-end gap-3 pt-4">
          <button
            type="button"
            className="px-4 py-2 text-sm rounded-lg border border-gray-200 text-gray-600 hover:bg-gray-100 transition"
          >
            Cancel
          </button>
  
          <button
            type="submit"
            className="px-5 py-2 text-sm rounded-lg bg-orange-500 text-white hover:bg-orange-600 transition"
          >
            {loader ? "Updating..." : "Update Brand"}
          </button>
        </div>
  
      </form>
    </div>
  </div>
  );
}
